parameters.jsCode:
const payload = $json;
const text = String(payload.message || '').trim();
const lower = text.toLowerCase();

const kbFromEnv = String(payload.support_kb_json || '');
const fallbackKb = {
  billing: {
    answer: 'For billing questions (invoice, copay, claims), our billing desk is available Mon-Fri 8am-6pm local time. Please share your patient ID and invoice number securely. You can also email billing@vishuhealthcare.example.',
    links: ['https://support.vishuhealthcare.example/billing']
  },
  appointment: {
    answer: 'To schedule, reschedule, or cancel appointments, use the patient portal or call +1-800-555-0100. Same-day slots depend on provider availability.',
    links: ['https://support.vishuhealthcare.example/appointments']
  },
  prescription: {
    answer: 'Prescription refill requests can be submitted in the portal under Medications. Typical turnaround is 24-48 hours after physician review.',
    links: ['https://support.vishuhealthcare.example/prescriptions']
  },
  records: {
    answer: 'Medical record requests require identity verification and consent. Submit request in portal under Records, or contact records@vishuhealthcare.example.',
    links: ['https://support.vishuhealthcare.example/medical-records']
  },
  insurance: {
    answer: 'For insurance coverage and eligibility, share your payer and plan details. We can verify benefits before your next visit.',
    links: ['https://support.vishuhealthcare.example/insurance']
  },
  technical: {
    answer: 'If you are having portal login or app issues, clear browser cache, retry password reset, and confirm MFA setup. If still blocked, contact support.',
    links: ['https://support.vishuhealthcare.example/portal-help']
  },
  general: {
    answer: 'I can help with appointments, billing, prescriptions, records, insurance, and portal access. Tell me your question in one sentence.',
    links: ['https://support.vishuhealthcare.example/help-center']
  }
};

let kb = fallbackKb;
if (kbFromEnv) {
  try {
    kb = JSON.parse(kbFromEnv);
  } catch (e) {
    kb = fallbackKb;
  }
}

const intents = [
  { key: 'billing', keywords: ['bill', 'billing', 'invoice', 'payment', 'copay', 'claim'] },
  { key: 'appointment', keywords: ['appointment', 'schedule', 'reschedule', 'cancel', 'doctor visit'] },
  { key: 'prescription', keywords: ['prescription', 'refill', 'medicine', 'medication', 'pharmacy'] },
  { key: 'records', keywords: ['record', 'medical record', 'lab result', 'report', 'test result'] },
  { key: 'insurance', keywords: ['insurance', 'coverage', 'benefit', 'payer', 'plan'] },
  { key: 'technical', keywords: ['login', 'password', 'portal', 'otp', 'mfa', 'app issue', 'technical'] }
];

let detectedIntent = 'general';
for (const intent of intents) {
  if (intent.keywords.some((k) => lower.includes(k))) {
    detectedIntent = intent.key;
    break;
  }
}

const kbEntry = kb[detectedIntent] || kb.general || fallbackKb.general;
const confidence = detectedIntent === 'general' ? 0.55 : 0.86;
const escalationNeeded = detectedIntent === 'general' || lower.includes('urgent') || lower.includes('emergency');

const responseText = [
  `Hi, this is ${payload.provider_name} virtual support.`,
  kbEntry.answer,
  escalationNeeded
    ? `If this is urgent, please call emergency services immediately. For live help, email ${payload.support_email}.`
    : `If you need a human agent, email ${payload.support_email}.`
].join(' ');

return {
  json: {
    ...payload,
    intent: detectedIntent,
    confidence,
    escalation_needed: escalationNeeded,
    knowledge_links: kbEntry.links || [],
    response_text: responseText,
    status: 'resolved_by_assistant',
    processed_at: new Date().toISOString()
  }
};

parameters.jsonBody:
={{ {
  customer_id: $json.customer_id,
